#!/usr/bin/env python3
"""
Workspace Self-Improvement Script
Run periodically to audit and improve the workspace code.

Crons into: memory maintenance, code quality, documentation updates.
"""

import os
import re
import json
from pathlib import Path
from datetime import datetime, timezone

WORKSPACE = Path(r"C:\Users\Zwmar\.openclaw\workspace")
REPORT_FILE = WORKSPACE / "memory" / "improvement_report.json"


def find_python_files():
    """Find all Python files in workspace, excluding venvs and caches."""
    files = []
    for p in WORKSPACE.rglob("*.py"):
        if any(x in str(p) for x in ["venv", ".venv", "__pycache__", "node_modules", ".git"]):
            continue
        files.append(p)
    return files


def find_markdown_files():
    """Find all markdown files."""
    return list(WORKSPACE.rglob("*.md"))


def check_file_quality(path: Path) -> dict:
    """Audit a single file for quality issues."""
    issues = []
    try:
        content = path.read_text(encoding="utf-8")
        lines = content.split("\n")

        # Check for TODO/FIXME without owners
        for i, line in enumerate(lines, 1):
            if re.match(r"^\s*(TODO|FIXME|XXX|HACK):", line.strip()):
                if "[" not in line:  # No owner tag like [Nova]
                    issues.append({"type": "untagged_todo", "line": i, "text": line.strip()[:80]})

        # Check for missing docstrings in functions
        if re.search(r"^def \w+\(", content) and not re.search(r'"""[^"]*"""', content[:500]):
            if "SKILL.md" not in str(path):  # Skills have their own format
                issues.append({"type": "missing_docstring", "count": len(re.findall(r"^def \w+\(", content, re.M))})

        # Check line lengths (soft limit at 120)
        long_lines = [(i + 1, len(l)) for i, l in enumerate(lines) if len(l) > 120]
        if long_lines:
            issues.append({"type": "long_lines", "count": len(long_lines), "examples": long_lines[:3]})

        # Check for print statements in non-demo code
        if "print(" in content and "demo" not in path.stem.lower():
            print_count = len(re.findall(r"print\(", content))
            if print_count > 3:
                issues.append({"type": "excessive_print", "count": print_count})

    except Exception as e:
        issues.append({"type": "read_error", "error": str(e)})

    return {"file": str(path.relative_to(WORKSPACE)), "issues": issues}


def check_memory_health() -> dict:
    """Check memory files for staleness and gaps."""
    memory_dir = WORKSPACE / "memory"
    if not memory_dir.exists():
        return {"status": "no_memory_dir", "files": [], "issues": []}

    today = datetime.now(timezone.utc).date()
    recent_files = []

    for f in memory_dir.glob("*.md"):
        mtime = datetime.fromtimestamp(f.stat().st_mtime, tz=timezone.utc).date()
        age = (today - mtime).days
        recent_files.append({"file": f.name, "age_days": age, "mtime": str(mtime)})

    # Check MEMORY.md for staleness
    mem_file = memory_dir / "MEMORY.md"
    mem_issues = []
    if mem_file.exists():
        content = mem_file.read_text(encoding="utf-8")
        if len(content) < 100:
            mem_issues.append("MEMORY.md is very small, may need population")
        # Check last update date in content
        date_match = re.search(r"(20\d\d-\d\d-\d\d)", content)
        if date_match:
            last_date = datetime.strptime(date_match.group(1), "%Y-%m-%d").date()
            age = (today - last_date).days
            if age > 7:
                mem_issues.append(f"MEMORY.md not updated in {age} days")
    else:
        mem_issues.append("MEMORY.md does not exist")

    return {
        "memory_files": len(recent_files),
        "files": recent_files,
        "issues": mem_issues,
    }


def check_identity_bootstrap() -> dict:
    """Check if IDENTITY.md and USER.md are properly filled in."""
    issues = []
    identity = WORKSPACE / "IDENTITY.md"
    user = WORKSPACE / "USER.md"

    if identity.exists():
        content = identity.read_text()
        if "Fill this in" in content or len(content) < 100:
            issues.append("IDENTITY.md not fully filled in")
    else:
        issues.append("IDENTITY.md missing")

    if user.exists():
        content = user.read_text()
        if "Learn about" in content or len(content) < 100:
            issues.append("USER.md not fully filled in")
    else:
        issues.append("USER.md missing")

    return {"issues": issues}


def generate_report() -> dict:
    """Run all checks and generate a report."""
    py_files = find_python_files()
    md_files = find_markdown_files()

    file_reports = [check_file_quality(f) for f in py_files]
    memory_health = check_memory_health()
    identity_health = check_identity_bootstrap()

    # Aggregate issue counts
    issue_counts = {}
    for fr in file_reports:
        for issue in fr["issues"]:
            t = issue["type"]
            issue_counts[t] = issue_counts.get(t, 0) + 1

    report = {
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "files_checked": len(py_files),
        "issue_counts": issue_counts,
        "file_reports": [fr for fr in file_reports if fr["issues"]],
        "memory_health": memory_health,
        "identity_health": identity_health,
        "top_issues": [
            {"type": t, "count": c}
            for t, c in sorted(issue_counts.items(), key=lambda x: -x[1])[:5]
        ],
    }

    # Save report
    REPORT_FILE.parent.mkdir(parents=True, exist_ok=True)
    REPORT_FILE.write_text(json.dumps(report, indent=2))

    return report


def apply_fixes(report: dict):
    """Apply auto-fixable issues."""
    fixed = []
    for fr in report["file_reports"]:
        path = WORKSPACE / fr["file"]
        if not path.exists():
            continue
        try:
            content = path.read_text(encoding="utf-8")
            original = content
            for issue in fr["issues"]:
                if issue["type"] == "long_lines":
                    # Wrap lines > 120 chars (simple heuristic)
                    lines = content.split("\n")
                    new_lines = []
                    for line in lines:
                        if len(line) > 120 and "http" not in line and not line.strip().startswith("#"):
                            # Try to wrap at a space
                            if "    " in line:
                                parts = line.split("    ", 1)
                                new_lines.append(parts[0].strip())
                                new_lines.append("    " + parts[1].strip())
                            else:
                                new_lines.append(line)
                        else:
                            new_lines.append(line)
                    content = "\n".join(new_lines)
            if content != original:
                path.write_text(content, encoding="utf-8")
                fixed.append(f"Wrapped long lines in {fr['file']}")
        except Exception as e:
            pass  # Skip files that can't be read

    return fixed


if __name__ == "__main__":
    report = generate_report()
    fixed = apply_fixes(report)
    summary = f"Workspace self-improve: {report['files_checked']} files checked, {len(fixed)} auto-fixed."
    if report["top_issues"]:
        summary += " | " + ", ".join(f"{i['type']}:{i['count']}" for i in report["top_issues"])
    print(summary)

